Here are the public test cases for feature10_1_skip_stages:
{
  "description": "Skipping individual release stages. The release pipeline's stages can be selectively skipped. Skipping the bump stage leaves the manifest version unchanged; skipping the changelog stage means no changelog file is created. Input describes release runs with combinations of skipped stages; output reports the resulting version and, where relevant, whether a changelog file exists afterward.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "changelogSeed": "legacy header format<a name=1.0.0>\n",
        "ops": [
          {
            "commit": "feat: first commit"
          }
        ],
        "args": [
          "--skip.bump",
          "true",
          "--skip.changelog",
          "true"
        ],
        "report": [
          "version"
        ]
      },
      "expected_output": "version=1.0.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "feat: first commit"
          }
        ],
        "args": [
          "--skip.changelog",
          "true"
        ],
        "report": [
          "version",
          "changelog"
        ]
      },
      "expected_output": "version=1.1.0\nchangelog=absent\n"
    }
  ]
}

