      "expected_output": "version=2.0.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "feat: a feature"
          }
        ],
        "args": [],
        "report": [
          "version"
        ]
      },
      "expected_output": "version=1.1.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "fix: a fix"
          }
        ],
        "args": [],
        "report": [
          "version"
        ]
      },
      "expected_output": "version=1.0.1\n"
    }
  ]
}

