Here are the public test cases for feature5_3_prerelease_progression:
{
  "description": "Sequential pre-release progression across several runs. Within one ongoing pre-release identifier, repeated runs increment the trailing pre-release counter (.0, .1, .2 ...) as long as the recommended underlying increment does not exceed the level the active pre-release already represents. When a higher-level increment is requested or recommended (e.g. moving from a patch pre-release to a minor pre-release), the base version is raised and the pre-release counter restarts at zero. Each run reports the version it produced. Input is an ordered list of runs, each with its commits and arguments; output reports one resulting version per run, in order.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "rounds": [
          {
            "ops": [
              {
                "commit": "fix: first patch"
              }
            ],
            "args": [
              "--release-as",
              "patch",
              "--prerelease",
              "dev"
            ]
          },
          {
            "ops": [
              {
                "commit": "fix: second patch"
              }
            ],
            "args": [
              "--prerelease",
              "dev"
            ]
          },
          {
            "ops": [
              {
                "commit": "feat: first new feat"
              }
            ],
            "args": [
              "--release-as",
              "minor",
              "--prerelease",
              "dev"
            ]
          },
          {
            "ops": [
              {
                "commit": "fix: third patch"
              }
            ],
            "args": [
              "--release-as",
              "minor",
              "--prerelease",
              "dev"
            ]
          },
          {
            "ops": [
              {
                "commit": "fix: forth patch"
              }
            ],
            "args": [
              "--prerelease",
              "dev"
            ]
          }
        ]
      },
      "expected_output": "version=1.0.1-dev.0\nversion=1.0.1-dev.1\nversion=1.1.0-dev.0\nversion=1.1.0-dev.1\nversion=1.1.0-dev.2\n"
    }
  ]
}

Here are the public test cases for feature6_1_changelog_section:
{
  "description": "Changelog section rendering for a single release. After a previous release tag exists, a new release's changelog document is generated. The document opens with the configured header line, then a release-section heading carrying the new version as a comparison link (whose URL is built from a configurable compare format and the previous/current tags) and a date, then grouped subsections of changes. Fix commits appear under a 'Bug Fixes' subsection and feature commits under a 'Features' subsection, each entry being the commit description followed by its short hash. Dates are rendered as the literal DATE and commit short hashes as the literal HASH to keep output stable. Input describes the manifest state, a seed changelog, the commit/tag history, and changelog formatting arguments; output is the rendered changelog document.",
  "cases": [
    {
      "input": {
        "kind": "changelog",
        "packageVersion": null,
        "changelogSeed": "",
        "ops": [
          {
            "commit": "feat: first commit"
          },
          {
            "tag": "v1.0.0"
          },
          {
            "commit": "fix: patch release"
          }
        ],
        "args": [
          "--changelogHeader=# Release Notes",
          "--compareUrlFormat=/compare/{{previousTag}}...{{currentTag}}"
        ]
      },
      "expected_output": "# Release Notes\n### [1.0.1](/compare/v1.0.0...v1.0.1) (DATE)\n\n\n### Bug Fixes\n\n* patch release HASH\n"
    },
    {
      "input": {
        "kind": "changelog",
        "packageVersion": null,
        "changelogSeed": "",
        "ops": [
          {
            "commit": "feat: first commit"
          },
          {
            "tag": "v1.0.0"
          },
          {
            "commit": "feat: a new feature"
          }
        ],
        "args": [
          "--changelogHeader=# Release Notes",
          "--compareUrlFormat=/compare/{{previousTag}}...{{currentTag}}"
        ]
      },
      "expected_output": "# Release Notes\n## [1.1.0](/compare/v1.0.0...v1.1.0) (DATE)\n\n\n### Features\n\n* a new feature HASH\n"
    }
  ]
}

