Here are the public test cases for feature6_5_changelog_custom_header:
{
  "description": "Custom changelog header text. The first line of the generated changelog document is a caller-supplied header string. Providing a custom header replaces the default header with the given text while the release sections below are unaffected. Input describes a release run with a custom header and compare format over an empty changelog and a single feature commit; output is the changelog beginning with the custom header.",
  "cases": [
    {
      "input": {
        "kind": "changelog",
        "packageVersion": null,
        "changelogSeed": "",
        "ops": [
          {
            "commit": "feat: first commit"
          }
        ],
        "args": [
          "--changelogHeader=# Pork Chop Log",
          "--compareUrlFormat=/compare/{{previousTag}}...{{currentTag}}"
        ]
      },
      "expected_output": "# Pork Chop Log\n## 1.1.0 (DATE)\n\n\n### Features\n\n* first commit HASH\n"
    }
  ]
}

Here are the public test cases for feature7_1_release_message_default:
{
  "description": "Release commit and annotated-tag message defaults. After a successful release the version-control commit recording the release and the annotated tag both carry a default message of the form 'chore(release): <version>'. Input describes a release run and requests the recorded commit message and the message of the newly created tag; output reports both.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "feat: first commit"
          },
          {
            "tag": "v1.0.0"
          },
          {
            "commit": "feat: new feature!"
          }
        ],
        "args": [],
        "report": [
          "commit_message",
          "tag_message"
        ]
      },
      "expected_output": "commit_message=chore(release): 1.1.0\ntag_message=chore(release): 1.1.0\n"
    }
  ]
}

Here are the public test cases for feature7_2_release_message_custom:
{
  "description": "Customising the release commit message. The release commit message template can be overridden via configuration or a command-line argument; the template's version placeholder is filled with the new version. Input describes a release run whose message template is overridden (in one case via a project configuration file, in another via a command-line argument); output reports the resulting recorded commit message.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "versionrc": {
          "releaseCommitMessageFormat": "This commit represents release: {{currentTag}}"
        },
        "ops": [
          {
            "commit": "feat: another commit addresses issue #1"
          }
        ],
        "args": [],
        "report": [
          "commit_message"
        ]
      },
      "expected_output": "commit_message=This commit represents release: 1.1.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "feat: another commit"
          }
        ],
        "args": [
          "--releaseCommitMessageFormat={{currentTag}} is the version."
        ],
        "report": [
          "commit_message"
        ]
      },
      "expected_output": "commit_message=1.1.0 is the version.\n"
    }
  ]
}

Here are the public test cases for feature7_3_legacy_message:
{
  "description": "Legacy percent-substitution in the release commit message. A deprecated message option uses the token %s as the version placeholder; every occurrence of %s in the supplied message is replaced by the new version. Input describes a release run whose legacy message option contains one or more %s tokens; output reports the resulting recorded commit message with all occurrences substituted.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
