          }
        ],
        "args": [
          "--message=V:%s"
        ],
        "report": [
          "commit_message"
        ]
      },
      "expected_output": "commit_message=V:1.1.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "ops": [
          {
            "commit": "feat: another commit"
          }
        ],
        "args": [
