  ]
}

Here are the public test cases for feature8_1_manifest_sync:
{
  "description": "Synchronising the version across auxiliary manifest files. Besides the primary package manifest, several other recognised metadata files (such as a front-end package descriptor, an extension manifest, a dependency lock descriptor, and a dependency shrinkwrap descriptor) have their recorded version field updated to the new release version when present. Input describes a release run with one such auxiliary file present alongside the primary manifest; output reports the new version and the version recorded in the auxiliary file.",
  "cases": [
    {
      "input": {
        "kind": "release",
        "packageVersion": "1.0.0",
        "manifests": {
          "bower.json": {
            "version": "1.0.0"
          }
        },
        "ops": [
          {
            "commit": "feat: first commit"
          },
          {
            "tag": "v1.0.0"
          },
          {
            "commit": "feat: new feature!"
          }
        ],
        "args": [],
