    {
      "input": {
        "kind": "release",
        "packageVersion": null,
        "ops": [
          {
            "commit": "feat: first commit"
          }
        ],
        "args": [],
        "report": [
          "tag"
        ]
      },
      "expected_output": "tag=v1.1.0\n"
    },
    {
      "input": {
        "kind": "release",
        "packageVersion": null,
        "ops": [
          {
            "tag": "v5.0.0"
          },
          {
            "tag": "v3.0.0"
          },
          {
            "commit": "feat: another commit"
          }
